    ('cat_reach_grab_toys', 3, 3, 'visible', true, true, 'Best for ring stack reach', 'Fisher-Price Rock-a-Stack Rings', 'Fisher-Price', 'Boots UK', 'https://www.boots.com/fisher-price-rock-a-stack-10024012', NULL, '£8.00', 'in_stock', '6 months+', 'A classic rocking base with colourful rings to grasp, mouth and place, suited to sitting babies practising hand to hand transfers.', 'Rings give a clear target for a sitting stretch and a wobbly base that answers a bat. You are not chasing perfect towers yet; you are chasing hold and place. Ring stack reach when they are ready for something that stays put on the mat.', 'Grasp and place rings.', 'Supervise small mouthing.', 'buy', true, 'Classic gift.', 'One set is enough.', 'Age 6m+ on listing.', 'strong', ARRAY['https://www.boots.com/fisher-price-rock-a-stack-10024012']::text[], 'none'),
    ('cat_reach_grab_toys', 4, 4, 'visible', true, true, 'Best for silicone monkey grip', 'Matchstick Monkey Original Teething Toy', 'Matchstick Monkey', 'Boots UK', 'https://www.boots.com/matchstick-monkey-original-teething-toy-grey-10207240', NULL, '£10.99', 'in_stock', '3 months+', 'A silicone monkey teether with a textured face and easy tail grip, made for sitting hands to grab, shake and gum during short floor play.', 'When the ball rolls away, a monkey that stays in the hand helps. Soft silicone invites mouthing after the grab at this age. Silicone monkey grip when you want one object that is both a reach target and a chew on the mat.', 'Grab then gum.', 'Clean regularly.', 'buy', true, 'Compact gift.', 'Skip if already buying for the teether card.', 'Supervise.', 'strong', ARRAY['https://www.boots.com/matchstick-monkey-original-teething-toy-grey-10207240']::text[], 'none'),
    ('cat_reach_grab_toys', 5, 5, 'visible', true, true, 'Best for take along rattle', 'Bright Starts Having a Ball Take Along Rattle', 'Bright Starts', 'Smyths Toys', 'https://www.smythstoys.com/uk/en-gb/toys/baby-and-preschool/baby-toys/bright-starts-having-a-ball-take-along-rattle/p/179219', NULL, '£7.00', 'in_stock', '3 months+', 'A bright easy grip rattle ball with beads inside, sized for sitting hands to shake on the go between mat sessions.', 'Not every reach happens on the mat. A light rattle that survives the bag keeps the same grab job in the café queue. Take along rattle when home already has an Oball and you want sound without another soft ball.', 'Portable shake and grab.', 'Volume can be sharp indoors.', 'buy', true, 'Small add-on.', 'Bright Starts already appears once above; this is a different job.', 'Supervise.', 'good', ARRAY['https://www.smythstoys.com/uk/en-gb/toys/baby-and-preschool/baby-toys/bright-starts-having-a-ball-take-along-rattle/p/179219']::text[], 'none'),
    ('cat_safety_gates', 1, 1, 'visible', true, false, 'Best for easy pressure fit', 'Munchkin Lindam Easy Fit Plus Deluxe Safety Gate', 'Munchkin Lindam', 'Boots UK', 'https://www.boots.com/munchkin-lindam-easy-fit-plus-deluxe-stair-gate-10220327', NULL, 'See Boots', 'in_stock', 'Suitable for children up to 24 months (EN 1930)', 'A pressure fit stair gate with one hand opening, made to close doorways before crawling turns into exploring every room.', 'Mobility is arriving and rooms suddenly look risky. A gate you can open with one hand while carrying a baby earns daily use. Easy pressure fit when you need a doorway closed this week without drilling yet. Keep Munchkin Lindam Easy Fit in easy reach for the next short try.', 'Doorway control.', 'Follow wall cup guidance on listing.', 'buy', false, NULL, 'Parent buy; measure opening.', 'Install per EN guidance; never on stairs incorrectly.', 'strong', ARRAY['https://www.boots.com/munchkin-lindam-easy-fit-plus-deluxe-stair-gate-10220327']::text[], 'none'),
    ('cat_safety_gates', 2, 2, 'visible', true, true, 'Best for true pressure indicator', 'BabyDan Premier True Pressure Fit Safety Gate White', 'BabyDan', 'Boots UK', 'https://www.boots.com/babydan-premier-true-pressure-fit-safety-gate-white-10220688', NULL, 'See Boots', 'in_stock', 'EN 1930; children up to 24 months', 'A BabyDan Premier pressure gate with pressure indicators, designed to fit without wall cups on suitable openings within the stated width.', 'Pressure indicators take guesswork out of a tight fit on the posts. Measure twice before you buy extensions. True pressure indicator when you want clear install feedback and a Premier frame you can buy at Boots. Leave BabyDan Premier True Pressure out where they can find it again tomorrow.', 'Indicator-led install.', 'Width range matters; extensions extra.', 'buy', false, NULL, 'Measure opening.', 'EN install rules.', 'strong', ARRAY['https://www.boots.com/babydan-premier-true-pressure-fit-safety-gate-white-10220688']::text[], 'none'),
    ('cat_safety_gates', 3, 3, 'visible', true, true, 'Best for auto close latch', 'Lindam Sure Shut Orto Safety Gate', 'Lindam', 'Boots UK', 'https://www.boots.com/lindam-sure-shut-orto-safety-gate-10207295', NULL, 'See Boots', 'in_stock', 'EN 1930 up to 24 months', 'A pressure fit gate with auto close behaviour, helping the latch finish when hands are full during busy hallway days.', 'Gates that only half latch fail quietly in busy hallways. Auto close helps when you are carrying laundry and a baby. Auto close latch when doorway traffic is constant and you forget the final push. One short go with Lindam Sure Shut Orto is enough before you tidy away.', 'Hands-full latching.', 'Still check closed every time.', 'buy', false, NULL, 'Parent buy.', 'Verify latch each use.', 'good', ARRAY['https://www.boots.com/lindam-sure-shut-orto-safety-gate-10207295']::text[], 'none'),
    ('cat_safety_gates', 4, 4, 'visible', true, true, 'Best for wider openings', 'Dreambaby Ava Extra Tall Safety Gate White', 'Dreambaby', 'Boots UK', 'https://www.boots.com/dreambaby-ava-extra-tall-safety-gate-white-10307280', NULL, 'See Boots', 'in_stock', 'EN safety gate guidance', 'An extra tall safety gate aimed at wider openings, for homes where a standard gate leaves a gap or feels too low.', 'Not every doorway matches a standard seventy five centimetre gate. Tall and wide options stop the endless gap hunt. Wider openings when your tape measure already failed a Premier base width at home. Stay nearby while they try Dreambaby Ava Extra Tall, then stop on a good note.', 'Non-standard openings.', 'Confirm exact width on PDP.', 'buy', false, NULL, 'Measure carefully.', 'Correct install width.', 'good', ARRAY['https://www.boots.com/dreambaby-ava-extra-tall-safety-gate-white-10307280']::text[], 'check_url'),
    ('cat_safety_gates', 5, 5, 'visible', true, true, 'Best for specialist gate shop', 'BabyDan Premier True Pressure Fit Gate Silver', 'BabyDan', 'Safetots', 'https://www.safetots.co.uk/babydan-premier-true-pressure-fit-gate-silver-79-6cm-86-5cm.html', NULL, '£52.90', 'in_stock', 'EN 1930 pressure gate', 'A BabyDan Premier silver pressure gate sold via a UK specialist with a clear width band including extension, for measured openings.', 'Specialist shops list width bands plainly on the product page. That helps when Boots colourways are out of stock. Specialist gate shop when you already trust Premier and need a specific centimetre pack. Put BabyDan Premier True Pressure where you both sit most evenings so the invite is easy.', 'Width-specific Premier.', 'Second BabyDan in Top 5.', 'buy', false, NULL, 'Same family as rank 2; different width/colour pack.', 'Measure opening.', 'good', ARRAY['https://www.safetots.co.uk/babydan-premier-true-pressure-fit-gate-silver-79-6cm-86-5cm.html']::text[], 'none'),
    ('cat_stacking_nesting_cups', 1, 1, 'visible', true, false, 'Best for classic nest stack', 'Munchkin Stacking Cups', 'Munchkin', 'Boots UK', 'https://www.boots.com/munchkin-stacking-cups-10116320', NULL, '£6.00', 'in_stock', '6 months+', 'A set of colourful plastic cups that nest for storage and stack for knock down play, sized for sitting hands practising in and out.', 'In and out is the new job on the mat. Cups that nest cleanly forgive wobbly towers and survive bath or floor play. Classic nest stack when you want one set that packs small and still invites pour and place together.', 'Nest and stack.', 'Supervise mouthing.', 'buy', true, 'Easy gift.', 'One cup set is enough.', '6m+ mark.', 'strong', ARRAY['https://www.boots.com/munchkin-stacking-cups-10116320']::text[], 'none'),
    ('cat_stacking_nesting_cups', 2, 2, 'visible', true, true, 'Best for bath pour stack', 'Munchkin Caterpillar Spillers Stacking Cups', 'Munchkin', 'Boots UK', 'https://www.boots.com/munchkin-caterpillar-spillers-bath-toy-10095140', NULL, '£8.00', 'in_stock', '9 months+', 'Seven numbered cups that link into a caterpillar, stack into a tower and pour water, bridging mat nesting into bath play.', 'Pour holes turn stacking into water play without a new toy language. Nine months on the listing sits at the top of this band. Bath pour stack when mat cups already exist and bath is the next place for in and out.', 'Stack and pour.', '9m+ mark - late in band.', 'buy', true, 'Bath gift.', 'Second Munchkin; different job from plain cups.', 'Bath supervise.', 'strong', ARRAY['https://www.boots.com/munchkin-caterpillar-spillers-bath-toy-10095140']::text[], 'check_age_fit'),
    ('cat_stacking_nesting_cups', 3, 3, 'visible', true, true, 'Best for early ring towers', 'Fisher-Price Rock-a-Stack Rings', 'Fisher-Price', 'Boots UK', 'https://www.boots.com/fisher-price-rock-a-stack-10024012', NULL, '£12.00', 'in_stock', '6 months+', 'A rocking ring stacker that teaches place and order before free cups, with a base that stays put on the mat.', 'Cups wander; a ring base stays put on the mat. Early place practice still feeds the same in and out idea. Early ring towers when free cups keep rolling under the sofa and you want a fixed stack target nearby.', 'Simple sturdy stack.', 'Confirm live title on Amazon.', 'buy', true, 'Material-led gift.', 'Skip duplicate cup sets.', 'Supervise.', 'good', ARRAY['https://www.boots.com/fisher-price-rock-a-stack-10024012']::text[], 'check_url'),
    ('cat_stacking_nesting_cups', 4, 4, 'visible', true, true, 'Best for easy grip ball', 'Bright Starts Oball Classic Easy-Grasp Toy', 'Bright Starts', 'Boots UK', 'https://www.boots.com/baby-einstein-oball-classic-easy-grasp-toy-10307276', NULL, '£16.00', 'in_stock', '6 months+', 'A light flexible ball with finger holes that sitting hands can grab during early place play beside nesting cups on the mat.', 'Cups need a partner object to put in and take out. Soft holes forgive clumsy aim. Easy grip ball when cup stacking is new and you want a second object that stays kind to gums. Stay nearby while they try Bright Starts Oball Classic, then stop on a good note.', 'Chew-friendly cups.', 'Pricier than plastic.', 'buy', true, 'Premium soft gift.', 'One silicone set is enough.', 'Food grade claim on listing.', 'good', ARRAY['https://www.boots.com/baby-einstein-oball-classic-easy-grasp-toy-10307276']::text[], 'none'),
    ('cat_stacking_nesting_cups', 5, 5, 'visible', true, true, 'Best for take along rattle', 'Bright Starts Having a Ball Take Along Rattle', 'Bright Starts', 'Smyths Toys', 'https://www.smythstoys.com/uk/en-gb/toys/baby-and-preschool/baby-toys/bright-starts-having-a-ball-take-along-rattle/p/179219', NULL, '£8.00', 'in_stock', '6 months+', 'A bright easy grip rattle ball with beads inside, sized for sitting hands to shake beside cup play on the go.', 'Not every in and out happens on the mat. A light rattle that survives the bag keeps grab practice between rooms. Take along rattle when home already has cups and you want sound without another nest set. Put Bright Starts Having a where you both sit most evenings so the invite is easy.', 'Ordered place practice.', 'Rings not cups - adjacent.', 'buy', true, 'Classic gift.', 'Adjacent stacking; prefer cups first.', '6m+.', 'strong', ARRAY['https://www.smythstoys.com/uk/en-gb/toys/baby-and-preschool/baby-toys/bright-starts-having-a-ball-take-along-rattle/p/179219']::text[], 'none'),
    ('cat_teethers', 1, 1, 'visible', true, false, 'Best for natural rubber classic', 'Sophie la Girafe Teething Toy', 'Sophie La Girafe', 'Boots UK', 'https://www.boots.com/sophie-la-girafe-teething-toy-10024008', NULL, '£15.00', 'in_stock', 'From birth', 'A soft natural rubber giraffe teether with squeak and easy limbs to gum, long used for early mouthing while sitting.', 'Mouthing is how they explore objects now. Soft limbs give more than one gum target without hard plastic edges. Natural rubber classic when you want a known chew shape that survives the bag and the highchair tray. Keep Sophie la Girafe Teething in easy reach for the next short try.', 'Primary gum chew.', 'Replace if damaged.', 'buy', true, 'Classic gift.', 'One Sophie is enough.', 'Supervise mouthing.', 'strong', ARRAY['https://www.boots.com/sophie-la-girafe-teething-toy-10024008']::text[], 'none'),
    ('cat_teethers', 2, 2, 'visible', true, true, 'Best for silicone monkey grip', 'Matchstick Monkey Original Teething Toy', 'Matchstick Monkey', 'Boots UK', 'https://www.boots.com/matchstick-monkey-original-teething-toy-grey-10207240', NULL, '£10.99', 'in_stock', '3 months+', 'A silicone monkey teether with a textured face and easy tail grip, made for gumming during sitting and tray time.', 'Silicone holds cold better from the fridge and cleans simply after sticky gums. The face texture gives gums a map. Silicone monkey grip when rubber Sophie is already in the bag and you want a washable second chew. Leave Matchstick Monkey Original Teething out where they can find it again tomorrow.', 'Silicone gumming.', 'Avoid extreme heat.', 'buy', true, 'UK favourite gift.', 'One monkey is enough.', '3m+ mark.', 'strong', ARRAY['https://www.boots.com/matchstick-monkey-original-teething-toy-grey-10207240']::text[], 'none'),
    ('cat_teethers', 3, 3, 'visible', true, true, 'Best for cool gel keys', 'Nuby Ice Gel Teether Keys', 'Nuby', 'Boots UK', 'https://www.boots.com/nuby-ice-gel-teether-keys-10024020', NULL, '£6.00', 'in_stock', '3 months+', 'A keyring style gel teether you chill in the fridge, giving cool gumming with several shapes for sitting hands to choose.', 'Cool gel is a different sensation from rubber or silicone for sore gums. Keys give a choice of edges in one hand. Cool gel keys when gums are angry and you want a fridge option beside the everyday chew. One short go with Nuby Ice Gel Teether is enough before you tidy away.', 'Chilled gumming.', 'Follow chill guidance; never freeze solid if listing warns.', 'buy', true, 'Small add-on.', 'Handy second chew.', 'Supervise gel teethers.', 'good', ARRAY['https://www.boots.com/nuby-ice-gel-teether-keys-10024020']::text[], 'none'),
    ('cat_teethers', 4, 4, 'visible', true, true, 'Best for simple rubber ring', 'Natursutten Original Rubber Teether', 'Natursutten', 'Boots UK', 'https://www.boots.com/natursutten-original-rubber-teether-10220660', NULL, '£8.00', 'in_stock', '0 months+', 'A simple natural rubber teething ring without characters, easy to hold and gum during quiet sitting spells on the sofa or mat.', 'Not every chew needs a face printed on it. A plain ring is quiet in the bag and honest in the hand. Simple rubber ring when character teethers are already plentiful and you want one quiet shape. Stay nearby while they try Natursutten Original Rubber Teether, then stop on a good note.', 'Minimal rubber chew.', 'Replace if bitten through.', 'buy', true, 'Quiet gift.', 'Minimalist option.', 'Supervise.', 'good', ARRAY['https://www.boots.com/natursutten-original-rubber-teether-10220660']::text[], 'none'),
    ('cat_teethers', 5, 5, 'visible', true, true, 'Best for chew safe grab ball', 'Bright Starts Oball Classic Easy-Grasp Toy', 'Bright Starts', 'Boots UK', 'https://www.boots.com/baby-einstein-oball-classic-easy-grasp-toy-10307276', NULL, '£12.00', 'in_stock', '0 months+', 'A light flexible ball covered in soft finger holes, easy for sitting hands to grab and gum during short chew sessions on the mat.', 'Reach and chew often share the same minute on the mat. Soft holes reward the grab without a separate teether hunt. Chew safe grab ball when you want one object that covers both jobs during a short sit. Put Bright Starts Oball Classic where you both sit most evenings so the invite is easy.', 'Dual grab chew.', 'Also on reach card.', 'buy', true, 'Dual job gift.', 'Skip if already bought for reach.', 'Supervise.', 'strong', ARRAY['https://www.boots.com/baby-einstein-oball-classic-easy-grasp-toy-10307276']::text[], 'none'),
    ('cat_tummy_time_wobbler', 1, 1, 'visible', true, false, 'Best for rock then sit', 'Fisher-Price 2-in-1 Rockin'' Tummy Time Otter', 'Fisher-Price', 'Boots UK', 'https://www.boots.com/fisher-price-2-in-1-rockin-tummy-time-otter-10320720', NULL, '£18.00', 'in_stock', 'From birth', 'A plush otter with a soft book and mirror that rocks as a roly poly once baby sits, bridging tummy time into bat at play.', 'Short tummy bursts still help, but sitting changes the job now. The otter starts as a propped view and becomes a rock when they push up to sit. Rock then sit when you want one soft toy that keeps working after tummy time ends.', 'Tummy to sit wobble.', 'Supervise plush mouthing.', 'buy', true, 'Soft gift.', 'One otter is enough.', 'Supervised floor play.', 'good', ARRAY['https://www.boots.com/fisher-price-2-in-1-rockin-tummy-time-otter-10320720']::text[], 'none'),
    ('cat_tummy_time_wobbler', 2, 2, 'visible', true, true, 'Best for roll under chest', 'Red Kite Tummy Time Roller Woodland Walk', 'Red Kite', 'Boots UK', 'https://www.boots.com/red-kite-tummy-time-roller-woodland-walk-10285190', NULL, '£15.00', 'in_stock', '0 months+', 'A soft woodland roller with textures and crinkle, made to prop under the chest during short tummy sessions before sitting practice.', 'A roller gives a gentle lift without a hard wedge on the mat. At seven to nine months you still use short tummy bursts between sits. Roll under chest when you want a soft prop that also rattles interest when they push up.', 'Soft tummy prop.', 'Never leave unsupervised on tummy.', 'buy', true, 'Practical soft gift.', 'Skip if you already own a roller.', 'Adult present.', 'good', ARRAY['https://www.boots.com/red-kite-tummy-time-roller-woodland-walk-10285190']::text[], 'none'),
    ('cat_tummy_time_wobbler', 3, 3, 'visible', true, true, 'Best for wedge with toys', 'Fisher-Price Grow-with-Me Tummy Time Llama', 'Fisher-Price', 'Boots UK', 'https://www.boots.com/fisher-price-grow-with-me-tummy-time-llama-10307290', NULL, '£25.00', 'in_stock', 'From birth', 'A soft llama wedge with detachable toys that props the chest for tummy work and later becomes a sit beside play friend.', 'Some babies need a clearer lift than a roller. Detachable toys keep the view interesting when neck work is short. Wedge with toys when tummy time still needs scaffolding and you want pieces you can move to the sit mat later.', 'Supported tummy view.', 'Fisher-Price already one above; different job.', 'buy', true, 'Larger gift.', 'Bigger footprint; check storage.', 'Supervise wedge use.', 'good', ARRAY['https://www.boots.com/fisher-price-grow-with-me-tummy-time-llama-10307290']::text[], 'none'),
    ('cat_tummy_time_wobbler', 4, 4, 'visible', true, true, 'Best for animated peek friend', 'Gund Baby Animated Peek-A-Boo Bear Flora', 'Gund', 'Boots UK', 'https://www.boots.com/gund-baby-animated-peek-a-boo-bear-flora-10220650', NULL, '£22.00', 'in_stock', '0 months+', 'A soft animated bear that covers and reveals her eyes, inviting bat at play and shared peek turns on the floor beside tummy time.', 'Wobbly interest is not only rollers. An animated peek friend keeps them looking forward during short floor stretches. Animated peek friend when you want soft cause and effect beside tummy work without a hard toy on the living room mat.', 'Floor interest beside tummy.', 'Batteries; volume.', 'buy', true, 'Character gift.', 'One animated plush is enough.', 'Supervise electronics.', 'good', ARRAY['https://www.boots.com/gund-baby-animated-peek-a-boo-bear-flora-10220650']::text[], 'none'),
    ('cat_tummy_time_wobbler', 5, 5, 'visible', true, true, 'Best for propped mat view', 'Bright Starts Tummy Time Prop Mat', 'Bright Starts', 'Smyths Toys', 'https://www.smythstoys.com/uk/en-gb/toys/baby-and-preschool/baby-toys/bright-starts-tummy-time-prop-mat/p/191600', NULL, '£20.00', 'in_stock', '0 months+', 'A tummy time mat with a soft prop pillow and dangling toys, giving a clear view target during short floor sessions.', 'A dedicated mat keeps tummy work from spreading across the whole living room. Prop and toys give a reason to lift the head before the next sit. Propped mat view when you want a defined tummy station rather than another plush.', 'Defined tummy station.', 'Larger to store.', 'buy', true, 'Bigger gift.', 'Skip if floor space is tight.', 'Supervise tummy.', 'good', ARRAY['https://www.smythstoys.com/uk/en-gb/toys/baby-and-preschool/baby-toys/bright-starts-tummy-time-prop-mat/p/191600']::text[], 'none')
  ) AS v(source_category_entity_id, pick_rank, longlist_rank, status, is_visible, is_locked, best_for_tag, product_name, brand, retailer, product_url, image_url, price_text, stock_status, age_mark_on_listing, product_description, ember_verdict, why_it_fits, caveats, buy_borrow_hold_off, gift_suitable, gift_note, ownership_note, safety_notes, evidence_tier, evidence_sources, founder_qa_flag)
)
INSERT INTO public.pl_stage3_picks (
  age_band_id,
  category_type_id,
  source_category_entity_id,
  pick_rank,
  longlist_rank,
  status,
  is_visible,
  is_locked,
  best_for_tag,
  product_name,
  brand,
  retailer,
  product_url,
  image_url,
  price_text,
  stock_status,
  age_mark_on_listing,
  product_description,
  ember_verdict,
  why_it_fits,
  caveats,
  buy_borrow_hold_off,
  gift_suitable,
  gift_note,
  ownership_note,
  safety_notes,
  evidence_tier,
  evidence_sources,
  founder_qa_flag,
  research_payload
)
SELECT
  '6-9m',
  ct.id,
  r.source_category_entity_id,
  r.pick_rank,
  r.longlist_rank,
  r.status,
  r.is_visible,
  r.is_locked,
  r.best_for_tag,
  r.product_name,
  r.brand,
  r.retailer,
  r.product_url,
  r.image_url,
  r.price_text,
  r.stock_status,
  r.age_mark_on_listing,
  r.product_description,
  r.ember_verdict,
  r.why_it_fits,
  r.caveats,
  r.buy_borrow_hold_off,
  r.gift_suitable,
  r.gift_note,
  r.ownership_note,
  r.safety_notes,
  r.evidence_tier,
  r.evidence_sources,
  r.founder_qa_flag,
  jsonb_build_object(
    'bundle_schema_version', 'stage3_ingestion_bundle_v1',
    'bundle_generated_at', '2026-07-24T11:05:58.915Z',
    'research_schema_version', 'ember_picks_research_v3',
    'source_category_entity_id', r.source_category_entity_id
  )
FROM stage3_rows r
JOIN public.pl_category_types ct
  ON ct.slug = r.source_category_entity_id
WHERE EXISTS (
  SELECT 1
  FROM public.pl_age_band_development_need_category_types abdnct
  WHERE abdnct.age_band_id = '6-9m'
    AND abdnct.category_type_id = ct.id
    AND abdnct.is_active = true
);

